import OpenAI from 'openai';
import { Vex } from 'vex-sdk';

// npm install openai vex-sdk
const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

// Next.js API route: pages/api/webhooks/assistant.ts
export default async function handler(req, res) {
  if (req.body.event.type !== 'run.completed') {
    res.status(200).end();
    return;
  }

  const run = req.body.data.object;
  const tenantId = run.metadata?.tenant_id;

  // Verify file search isolation
  const filesRetrieved = run.required_action?.submit_tool_outputs?.tool_outputs || [];
  const verification = await vex.verify({
    name: 'gdpr-file-isolation',
    input: {
      files: filesRetrieved.map(f => f.file_id),
      tenantId
    },
    context: { regulation: 'GDPR' }
  });

  if (!verification.passed) {
    await openai.beta.threads.runs.cancel(run.thread_id, run.id);
    res.status(403).json({ blocked: true });
    return;
  }

  res.status(200).json({ verified: true, receipt: verification.receipt });
}

from openai import OpenAI
from vex_sdk import VexClient

client = OpenAI()
vex = VexClient(api_key='vex-api-key')

def check_thread_compliance(thread_id: str, tenant_id: str):
    thread = client.beta.threads.retrieve(thread_id)
    message_count = len(client.beta.threads.messages.list(thread_id=thread_id).data)

    # Vex policy check for context limits
    result = vex.verify({
        'name': 'soc2-thread-limits',
        'input': {'message_count': message_count, 'tenant_id': tenant_id},
        'policy': 'message_count <= 50'
    })

    if not result.passed:
        # Archive and create new thread
        client.beta.threads.create()
        return {'action': 'rotate_thread', 'receipt': result.receipt}

    return {'status': 'compliant'}

# Call before each run
check_thread_compliance('thread_abc123', 'tenant_enterprise_x')
